from functools import lru_cache

def longest_common_subsequence_length(text1: str, text2: str) -> int:
    @lru_cache(maxsize=None)
    def dp(i, j):
        if i == -1 or j == -1:
            return 0
        if text1[i] == text2[j]:
            return dp(i - 1, j - 1) + 1
        else:
            return max(dp(i - 1, j), dp(i, j - 1))
    return dp(len(text1) - 1, len(text2) - 1)
