    private static int[][] matrixA;
    private static int[][] matrixB;
    private static int[][] result;
    private static int size;

    public static void main(String[] args) {
        size = 3; // Example size, can be changed
        matrixA = generateRandomMatrix(size);
        matrixB = generateRandomMatrix(size);
        result = new int[size][size];

        System.out.println("Matrix A:");
        printMatrix(matrixA);
        System.out.println("Matrix B:");
        printMatrix(matrixB);

        Thread[] threads = new Thread[size];
        for (int i = 0; i < size; i++) {
            final int row = i;
            threads[i] = new Thread(() -> multiplyRow(row));
            threads[i].start();
        }

        for (Thread thread : threads) {
            try {
                thread.join();
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }

        System.out.println("Result:");
        printMatrix(result);
    }

    private static int[][] generateRandomMatrix(int size) {
        Random random = new Random();
        int[][] matrix = new int[size][size];
        for (int i = 0; i < size; i++) {
            for (int j = 0; j < size; j++) {
                matrix[i][j] = random.nextInt(10);
            }
        }
        return matrix;
    }

    private static synchronized void multiplyRow(int row) {
        for (int col = 0; col < size; col++) {
            for (int k = 0; k < size; k++) {
                result[row][col] += matrixA[row][k] * matrixB[k][col];
            }
        }
    }

    private static void printMatrix(int[][] matrix) {
        for (int[] row : matrix) {
            for (int num : row) {
                System.out.print(num + " ");
            }
            System.out.println();
        }
    }
