```java
import javax.annotation.processing.*;
import javax.lang.model.SourceVersion;
import javax.lang.model.element.*;
import javax.lang.model.util.*;
import javax.tools.Diagnostic;
import java.io.IOException;
import java.io.Writer;
import java.util.*;
import java.util.stream.Collectors;

@SupportedAnnotationTypes("com.example.GrpcService")
@SupportedSourceVersion(SourceVersion.RELEASE_11)
public class GrpcStubGeneratorProcessor extends AbstractProcessor {

    @Override
    public boolean process(Set<? extends TypeElement> annotations, RoundEnvironment roundEnv) {
        for (TypeElement annotation : annotations) {
            Set<? extends Element> annotatedElements = roundEnv.getElementsAnnotatedWith(annotation);

            annotatedElements.stream()
                .filter(element -> element.getKind() == ElementKind.INTERFACE)
                .map(element -> (TypeElement) element)
                .forEach(this::generateGrpcStub);
        }
        return true;
    }

    private void generateGrpcStub(TypeElement serviceInterface) {
        String packageName = processingEnv.getElementUtils().getPackageOf(serviceInterface).toString();
        String className = serviceInterface.getSimpleName() + "GrpcStub";

        try (Writer writer = processingEnv.getFiler()
                .createSourceFile(packageName + "." + className)
                .openWriter()) {

            writer.write("package " + packageName + ";\n\n");
            writer.write("import io.grpc.stub.AbstractStub;\n");
            writer.write("import io.grpc.Channel;\n\n");
            writer.write("public class " + className + " extends AbstractStub<" + className + "> {\n\n");

            writer.write("    protected " + className + "(Channel channel) {\n");
            writer.write("        super(channel);\n");
            writer.write("    }\n\n");

            writer.write("    @Override\n");
            writer.write("    protected " + className + " build(Channel channel, io.grpc.CallOptions callOptions) {\n");
            writer.write("        return new " + className + "(channel);\n");
            writer.write("    }\n\n");

            serviceInterface.getEnclosedElements().stream()
                .filter(element -> element.getKind() == ElementKind.METHOD)
                .map(element -> (ExecutableElement) element)
                .forEach(method -> generateMethod(writer, method));

            writer.write("}\n");
        } catch (IOException e) {
            processingEnv.getMessager().printMessage(Diagnostic.Kind.ERROR, 
                "Failed to generate gRPC stub: " + e.getMessage());
        }
    }

    private void generateMethod(Writer writer, ExecutableElement method) {
        try {
            String methodName = method.getSimpleName().toString();
            String returnType = method.getReturnType().toString();
            String params = method.getParameters().stream()
                .map(param -> param.asType().toString() + " " + param.getSimpleName())
                .collect(Collectors.joining(", "));

            writer.write("    public " + returnType + " " + methodName + "(" + params + ") {\n");
            writer.write("        // TODO: Implement gRPC call\n");
            writer.write("        throw new UnsupportedOperationException();\n");
            writer.write("    }\n\n");
        } catch (IOException e) {
            processingEnv.getMessager().printMessage(Diagnostic.Kind.ERROR, 
                "Failed to generate method: " + e.getMessage());
        }
    }
}
