import org.graalvm.polyglot.*;
import org.graalvm.polyglot.proxy.*;
import com.mongodb.reactivestreams.client.*;
import org.bson.*;
import org.reactivestreams.*;

public class JsonataMongoService {
    private final MongoClient mongoClient;
    private final Context polyglotContext;

    public JsonataMongoService(String connectionString) {
        this.mongoClient = MongoClients.create(connectionString);
        this.polyglotContext = Context.newBuilder()
            .allowAllAccess(true)
            .build();
    }

    public Publisher<Document> mapChangeStream(String dbName, String collName, String jsonataQuery) {
        return SubscriberWithBackpressure.create(subscriber -> {
            MongoDatabase database = mongoClient.getDatabase(dbName);
            MongoCollection<Document> collection = database.getCollection(collName);

            collection.watch().subscribe(new Subscriber<ChangeStreamDocument<Document>>() {
                private Subscription subscription;

                @Override
                public void onSubscribe(Subscription s) {
                    this.subscription = s;
                    subscriber.onSubscribe(new Subscription() {
                        @Override
                        public void request(long n) {
                            subscription.request(n);
                        }

                        @Override
                        public void cancel() {
                            subscription.cancel();
                        }
                    });
                }

                @Override
                public void onNext(ChangeStreamDocument<Document> changeEvent) {
                    try {
                        Value jsonata = polyglotContext.eval("jsonata", jsonataQuery);
                        Value result = jsonata.execute(ProxyObject.fromMap(changeEvent.getFullDocument()));
                        subscriber.onNext(Document.parse(result.asString()));
                    } catch (Exception e) {
                        subscriber.onError(e);
                    }
                }

                @Override
                public void onError(Throwable t) {
                    subscriber.onError(t);
                }

                @Override
                public void onComplete() {
                    subscriber.onComplete();
                }
            });
        });
    }

    public void close() {
        mongoClient.close();
        polyglotContext.close();
    }
}
